from fastapi import FastAPI, Depends, HTTPException


async def get_token():
    # simulates bearer token validation
    return 'abc-token'


def build_app():
    app = FastAPI()

    # BUG: Depends(get_token()) invokes the function; should be Depends(get_token)
    @app.get("/items", dependencies=[Depends(get_token())])
    async def list_items():
        return {'items': []}

    @app.get("/health")
    async def health():
        return {'ok': True}

    return app


def main():
    app = build_app()
    print(app)


if __name__ == '__main__':
    main()
